PRAGMA foreign_keys=ON;
CREATE TABLE scanner_areas(id INTEGER PRIMARY KEY AUTOINCREMENT,nombre TEXT UNIQUE,activo INTEGER DEFAULT 1,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE scanners(id INTEGER PRIMARY KEY AUTOINCREMENT,codigo TEXT UNIQUE,codigo_qr TEXT UNIQUE,tag_original TEXT UNIQUE,marca TEXT,modelo TEXT,estado TEXT,numero_serie TEXT UNIQUE,imei TEXT UNIQUE,telefono TEXT,iccid TEXT UNIQUE,red TEXT,plan TEXT,actividad_habitual TEXT,area_habitual TEXT,ubicacion TEXT,antiguedad_descriptiva TEXT,observaciones TEXT,fotografia_principal TEXT,area_id INTEGER,area_organizacional_id INTEGER,indice_conservacion INTEGER,activo INTEGER DEFAULT 1,created_by INTEGER,updated_by INTEGER,deactivated_at TEXT,deleted_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE areas_organizacionales(id INTEGER PRIMARY KEY AUTOINCREMENT,clave TEXT UNIQUE,nombre TEXT,activo INTEGER DEFAULT 1);
CREATE TABLE scanner_movimientos(id INTEGER PRIMARY KEY AUTOINCREMENT,scanner_id INTEGER,folio TEXT UNIQUE,estado TEXT,persona_entrega_nombre TEXT,supervisor_nombre TEXT,responsable_entrega_nombre TEXT,numero_empleado TEXT,area_id INTEGER,area_nombre TEXT,turno TEXT,entregado_at TEXT,recibido_at TEXT,vence_at TEXT,entrega_registrada_por INTEGER,recepcion_registrada_por INTEGER,devolucion_recibida_por_nombre TEXT,responsable_recepcion_nombre TEXT,duracion_segundos INTEGER,observaciones TEXT,cancelado_por INTEGER,cancelado_at TEXT,motivo_cancelacion TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX one_open ON scanner_movimientos(scanner_id) WHERE estado='abierto';
CREATE TABLE scanner_inspecciones(id INTEGER PRIMARY KEY AUTOINCREMENT,movimiento_id INTEGER,scanner_id INTEGER,tipo TEXT,bateria_porcentaje INTEGER,calificacion INTEGER,observaciones TEXT,firma_usuario_evidencia_id INTEGER,firma_responsable_evidencia_id INTEGER,inspeccionada_at TEXT,registrada_por INTEGER,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(movimiento_id,tipo));
CREATE TABLE scanner_inspeccion_detalles(id INTEGER PRIMARY KEY AUTOINCREMENT,inspeccion_id INTEGER,componente TEXT,estado TEXT,valor_numerico REAL,valor_texto TEXT,observaciones TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(inspeccion_id,componente));
CREATE TABLE scanner_incidencias(id INTEGER PRIMARY KEY AUTOINCREMENT,scanner_id INTEGER,movimiento_id INTEGER,tipo TEXT,severidad TEXT,descripcion TEXT,estado TEXT,reportado_por_nombre TEXT,registrada_por INTEGER,reportada_at TEXT,resolucion TEXT,resuelta_por INTEGER,resuelta_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE scanner_evidencias(id INTEGER PRIMARY KEY AUTOINCREMENT,scanner_id INTEGER,movimiento_id INTEGER,inspeccion_id INTEGER,incidencia_id INTEGER,mantenimiento_id INTEGER,tipo TEXT,ruta_storage TEXT,mime_type TEXT,tamano_bytes INTEGER,hash_sha256 TEXT,capturada_at TEXT,registrada_por INTEGER,activo INTEGER,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE auditoria_eventos(id INTEGER PRIMARY KEY AUTOINCREMENT,usuario_id INTEGER,accion TEXT,modulo TEXT,entidad TEXT,entidad_id INTEGER,resultado TEXT,valor_anterior_json TEXT,valor_nuevo_json TEXT,metadata_json TEXT,ip TEXT,request_id TEXT,session_fingerprint TEXT,created_at TEXT);
CREATE TABLE scanner_estado_historial(id INTEGER PRIMARY KEY AUTOINCREMENT,scanner_id INTEGER,estado_anterior TEXT,estado_nuevo TEXT,motivo TEXT,entidad_origen TEXT,entidad_origen_id INTEGER,registrado_por INTEGER,changed_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE scanner_mantenimientos(id INTEGER PRIMARY KEY AUTOINCREMENT,scanner_id INTEGER,estado TEXT,motivo TEXT,tecnico_proveedor TEXT,diagnostico TEXT,costo REAL,iniciado_at TEXT,fecha_estimada TEXT,finalizado_at TEXT,resultado TEXT,estado_final TEXT,registrada_por INTEGER,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE scanner_incidencia_seguimientos(id INTEGER PRIMARY KEY AUTOINCREMENT,incidencia_id INTEGER,estado_anterior TEXT,estado_nuevo TEXT,comentario TEXT,registrado_por INTEGER,created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE scanner_inspeccion_diferencias(id INTEGER PRIMARY KEY AUTOINCREMENT,movimiento_id INTEGER,inspeccion_entrega_id INTEGER,inspeccion_recepcion_id INTEGER,componente TEXT,valor_anterior TEXT,valor_nuevo TEXT,clasificacion TEXT,requiere_revision INTEGER,confirmada_por INTEGER,created_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(movimiento_id,componente));
